def lru_cache_sim(queries: list, capacity: int) -> list:
    from collections import OrderedDict
    cache = OrderedDict()
    res = []
    for q in queries:
        if q[0] == 'PUT':
            k, v = q[1], q[2]
            if k in cache:
                cache.move_to_end(k)
            cache[k] = v
            if len(cache) > capacity:
                cache.popitem(last=False)
            res.append(None)
        elif q[0] == 'GET':
            k = q[1]
            if k in cache:
                cache.move_to_end(k)
                res.append(cache[k])
            else:
                res.append(-1)
    return res

def count_word_frequencies(text: str) -> dict:
    import re
    words = re.findall(r'\b\w+\b', text.lower())
    freq = {}
    for w in words:
        freq[w] = freq.get(w, 0) + 1
    return freq

def moving_average(data: list, window: int) -> list:
    if not data or window <= 0:
        return []
    result = []
    for i in range(len(data)):
        start = max(0, i - window + 1)
        subset = data[start:i+1]
        result.append(sum(subset) / len(subset))
    return result

def is_valid_sudoku(board: list) -> bool:
    rows = [set() for _ in range(9)]
    cols = [set() for _ in range(9)]
    boxes = [set() for _ in range(9)]

    for r in range(9):
        for c in range(9):
            val = board[r][c]
            if val == '.':
                continue
            box_idx = (r // 3) * 3 + (c // 3)
            if val in rows[r] or val in cols[c] or val in boxes[box_idx]:
                return False
            rows[r].add(val)
            cols[c].add(val)
            boxes[box_idx].add(val)
    return True

def topological_sort(num_nodes: int, edges: list) -> list:
    from collections import defaultdict, deque
    adj = defaultdict(list)
    indegree = {i: 0 for i in range(num_nodes)}
    for u, v in edges:
        adj[u].append(v)
        indegree[v] += 1

    queue = deque([k for k, v in indegree.items() if v == 0])
    result = []

    while queue:
        node = queue.popleft()
        result.append(node)
        for neighbor in adj[node]:
            indegree[neighbor] -= 1
            if indegree[neighbor] == 0:
                queue.append(neighbor)

    return result if len(result) == num_nodes else []

def levenshtein_distance(s1: str, s2: str) -> int:
    m, n = len(s1), len(s2)
    dp = [[0] * (n + 1) for _ in range(m + 1)]
    for i in range(m + 1):
        dp[i][0] = i
    for j in range(n + 1):
        dp[0][j] = j

    for i in range(1, m + 1):
        for j in range(1, n + 1):
            if s1[i - 1] == s2[j - 1]:
                dp[i][j] = dp[i - 1][j - 1]
            else:
                dp[i][j] = 1 + min(dp[i - 1][j], dp[i][j - 1], dp[i - 1][j - 1])
    return dp[m][n]

def find_kth_largest(nums: list, k: int) -> int:
    import heapq
    min_heap = []
    for num in nums:
        heapq.heappush(min_heap, num)
        if len(min_heap) > k:
            heapq.heappop(min_heap)
    return min_heap[0]

def calculate_shipping(weight_kg: float, zone: str, express: bool = False) -> float:
    if weight_kg <= 0:
        raise ValueError("weight_kg must be positive")
    rates = {
        "local": (4.0, 1.25),
        "domestic": (7.5, 2.0),
        "international": (15.0, 4.5),
    }
    if zone not in rates:
        raise ValueError("unsupported zone")
    base, extra_rate = rates[zone]
    cost = base + max(0.0, weight_kg - 1.0) * extra_rate
    if express:
        cost *= 1.75
    return round(cost, 2)

