def slugify(text: str, max_length: int = 50) -> str:
    if max_length <= 0:
        return ""
    normalized = unicodedata.normalize("NFKD", text)
    ascii_text = normalized.encode("ascii", "ignore").decode("ascii")
    slug = re.sub(r"[^a-z0-9]+", "-", ascii_text.lower()).strip("-")
    return slug[:max_length].rstrip("-")

def batched(items, size: int):
    if size <= 0:
        raise ValueError("size must be positive")
    batch = []
    for item in items:
        batch.append(item)
        if len(batch) == size:
            yield tuple(batch)
            batch.clear()
    if batch:
        yield tuple(batch)

class BankAccount:
    def __init__(self, owner: str, opening_balance: float = 0.0):
        if opening_balance < 0:
            raise ValueError("opening balance cannot be negative")
        self.owner = owner
        self.balance = float(opening_balance)
        self._history = []

    def deposit(self, amount: float) -> float:
        if amount <= 0:
            raise ValueError("deposit must be positive")
        self.balance += amount
        self._history.append(("deposit", amount))
        return self.balance

    def withdraw(self, amount: float) -> bool:
        if amount <= 0:
            raise ValueError("withdrawal must be positive")
        if amount > self.balance:
            return False
        self.balance -= amount
        self._history.append(("withdraw", amount))
        return True

    @property
    def history(self) -> tuple:
        return tuple(self._history)

import json

def load_threshold(path: str, default: int = 10) -> int:
    try:
        with open(path, "r", encoding="utf-8") as handle:
            payload = json.load(handle)
    except FileNotFoundError:
        return default
    value = payload.get("threshold", default)
    if isinstance(value, bool) or not isinstance(value, int):
        raise ValueError("threshold must be an integer")
    if value < 0:
        raise ValueError("threshold cannot be negative")
    return value

def fetch_active_user(db, user_id: int):
    if user_id <= 0:
        raise ValueError("user_id must be positive")
    row = db.fetch_one("users", id=user_id)
    if row is None:
        raise LookupError("user not found")
    if not row.get("active", False):
        return None
    return {"id": row["id"], "name": row["name"]}

def parse_semver(value: str) -> tuple:
    core = value.split("+", 1)[0]
    version, separator, prerelease = core.partition("-")
    parts = version.split(".")
    if len(parts) != 3 or any(not part.isdigit() for part in parts):
        raise ValueError("invalid semantic version")
    numbers = tuple(int(part) for part in parts)
    if any(number < 0 for number in numbers):
        raise ValueError("invalid semantic version")
    return numbers, prerelease if separator else None

def rotate_matrix_clockwise(matrix: list) -> list:
    if not matrix:
        return []
    width = len(matrix[0])
    if width == 0:
        return []
    if any(len(row) != width for row in matrix):
        raise ValueError("matrix must be rectangular")
    return [[matrix[row][column] for row in range(len(matrix) - 1, -1, -1)] for column in range(width)]

def deduplicate_records(records: list, key: str) -> list:
    latest = {}
    order = []
    for record in records:
        if key not in record:
            raise KeyError(key)
        value = record[key]
        if value not in latest:
            order.append(value)
        latest[value] = dict(record)
    return [latest[value] for value in order]

class SlidingWindowLimiter:
    def __init__(self, limit: int, window_seconds: float):
        if limit <= 0 or window_seconds <= 0:
            raise ValueError("limit and window must be positive")
        self.limit = limit
        self.window_seconds = window_seconds
        self._events = {}

    def allow(self, key: str, now: float) -> bool:
        recent = [stamp for stamp in self._events.get(key, []) if now - stamp < self.window_seconds]
        if len(recent) >= self.limit:
            self._events[key] = recent
            return False
        recent.append(now)
        self._events[key] = recent
        return True

    def reset(self, key: str) -> None:
        self._events.pop(key, None)

def two_sum_indices(nums, target):
    seen = {}
    for j, value in enumerate(nums):
        need = target - value
        if need in seen:
            return (seen[need], j)
        if value not in seen:
            seen[value] = j
    return None

def merge_intervals(intervals):
    items = []
    for start, end in intervals:
        if start > end:
            raise ValueError("start must be <= end")
        items.append((start, end))
    items.sort()
    merged = []
    for start, end in items:
        if not merged or start > merged[-1][1]:
            merged.append([start, end])
        else:
            merged[-1][1] = max(merged[-1][1], end)
    return [tuple(x) for x in merged]

def group_anagrams(words):
    groups = {}
    order = []
    for word in words:
        key = tuple(sorted(word))
        if key not in groups:
            groups[key] = []
            order.append(key)
        groups[key].append(word)
    return [groups[key] for key in order]

def run_length_encode(text):
    if not text:
        return []
    result = []
    current = text[0]
    count = 1
    for ch in text[1:]:
        if ch == current:
            count += 1
        else:
            result.append((current, count))
            current, count = ch, 1
    result.append((current, count))
    return result

def is_balanced(text):
    pairs = {")": "(", "]": "[", "}": "{"}
    opening = set(pairs.values())
    stack = []
    for ch in text:
        if ch in opening:
            stack.append(ch)
        elif ch in pairs:
            if not stack or stack.pop() != pairs[ch]:
                return False
    return not stack

def rotate_clockwise(matrix):
