    return [list(row) for row in zip(*matrix[::-1])]

def top_k_frequent(items, k):
    if k <= 0:
        return []
    counts = {}
    first = {}
    for i, item in enumerate(items):
        counts[item] = counts.get(item, 0) + 1
        first.setdefault(item, i)
    ordered = sorted(counts, key=lambda x: (-counts[x], first[x]))
    return ordered[:k]

def flatten_dict(data, sep="."):
    result = {}

    def walk(obj, prefix):
        if isinstance(obj, dict):
            if not obj and prefix:
                result[prefix] = {}
                return
            for key, value in obj.items():
                new_key = str(key) if not prefix else prefix + sep + str(key)
                walk(value, new_key)
        else:
            result[prefix] = obj

    walk(data, "")
    return result

from collections import OrderedDict

class LRUCache:
    def __init__(self, capacity):
        if not isinstance(capacity, int) or isinstance(capacity, bool) or capacity <= 0:
            raise ValueError("capacity must be a positive integer")
        self.capacity = capacity
        self._data = OrderedDict()

    def get(self, key):
        if key not in self._data:
            return None
        self._data.move_to_end(key)
        return self._data[key]

    def put(self, key, value):
        if key in self._data:
            self._data.move_to_end(key)
        self._data[key] = value
        if len(self._data) > self.capacity:
            self._data.popitem(last=False)

    def __len__(self):
        return len(self._data)

def safe_divide_records(records):
    result = []
    for numerator, denominator in records:
        try:
            result.append(numerator / denominator)
        except ZeroDivisionError:
            result.append("division_by_zero")
        except (TypeError, ValueError):
            result.append("invalid_operand")
    return result

from datetime import datetime

def parse_log_lines(lines):
    result = []
    for line_no, raw in enumerate(lines, 1):
        if not raw.strip():
            continue
        parts = raw.split("|", 2)
        if len(parts) != 3:
            raise ValueError(f"invalid log line {line_no}")
        ts_text, level, message = (part.strip() for part in parts)
        try:
            timestamp = datetime.strptime(ts_text, "%Y-%m-%d %H:%M:%S")
        except ValueError as exc:
            raise ValueError(f"invalid log line {line_no}") from exc
        if not level:
            raise ValueError(f"invalid log line {line_no}")
        result.append({
            "timestamp": timestamp,
            "level": level.upper(),
            "message": message,
        })
    return result

from functools import wraps

def retry(max_attempts, exceptions=(Exception,)):
    if not isinstance(max_attempts, int) or isinstance(max_attempts, bool) or max_attempts <= 0:
        raise ValueError("max_attempts must be a positive integer")

    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            for attempt in range(max_attempts):
                try:
                    return func(*args, **kwargs)
                except exceptions:
                    if attempt == max_attempts - 1:
                        raise
        return wrapper
    return decorator

from itertools import islice

def chunked(iterable, size):
    if not isinstance(size, int) or isinstance(size, bool) or size <= 0:
        raise ValueError("size must be a positive integer")
    iterator = iter(iterable)
    while True:
        chunk = list(islice(iterator, size))
        if not chunk:
            break
        yield chunk

def deep_get(data, path, default=None):
    if path == "":
        return data
    current = data
    for segment in path.split("."):
        if isinstance(current, dict):
            if segment not in current:
                return default
            current = current[segment]
        elif isinstance(current, (list, tuple)):
            try:
                index = int(segment)
            except ValueError:
                return default
            if str(index) != segment or index < 0 or index >= len(current):
                return default
            current = current[index]
        else:
            return default
    return current

def deduplicate_records(records, key):
    seen = set()
    result = []
    for record in records:
        value = record[key]
        if value not in seen:
            seen.add(value)
            result.append(dict(record))
    return result

from collections import deque

def sliding_window_max(nums, k):
    if not isinstance(k, int) or isinstance(k, bool) or k <= 0 or k > len(nums):
        raise ValueError("invalid window size")
    dq = deque()
    result = []
    for i, value in enumerate(nums):
        while dq and dq[0] <= i - k:
            dq.popleft()
        while dq and nums[dq[-1]] <= value:
            dq.pop()
        dq.append(i)
        if i >= k - 1:
            result.append(nums[dq[0]])
    return result

import csv
import io
from decimal import Decimal, InvalidOperation

def summarize_csv(text):
    reader = csv.DictReader(io.StringIO(text))
    if reader.fieldnames is None:
        raise ValueError("missing header")
    normalized = [name.strip() for name in reader.fieldnames]
    if "category" not in normalized or "amount" not in normalized:
        raise ValueError("required headers: category, amount")
    mapping = dict(zip(reader.fieldnames, normalized))
    result = {}
    for raw_row in reader:
        if not raw_row or all((v is None or not v.strip()) for v in raw_row.values()):
            continue
        row = {mapping[k]: v for k, v in raw_row.items()}
        category = (row.get("category") or "").strip()
        amount_text = (row.get("amount") or "").strip()
        if not category:
            raise ValueError("empty category")
        try:
            amount = Decimal(amount_text)
        except (InvalidOperation, ValueError):
            raise ValueError("invalid amount")
        result[category] = result.get(category, Decimal("0")) + amount
    return result

import heapq

def dependency_order(graph):
    nodes = set(graph)
    for deps in graph.values():
        nodes.update(deps)

    indegree = {node: 0 for node in nodes}
    dependents = {node: [] for node in nodes}

    for node, deps in graph.items():
        unique_deps = set(deps)
        indegree[node] += len(unique_deps)
        for dep in unique_deps:
            dependents[dep].append(node)

    heap = [(str(node), i, node) for i, node in enumerate(nodes) if indegree[node] == 0]
    heapq.heapify(heap)
    result = []

    while heap:
        _, _, node = heapq.heappop(heap)
        result.append(node)
        for nxt in dependents[node]:
            indegree[nxt] -= 1
            if indegree[nxt] == 0:
                heapq.heappush(heap, (str(nxt), len(result) + len(heap), nxt))

    if len(result) != len(nodes):
        raise ValueError("cycle detected")
    return result

class MemoizedFibonacci:
    def __init__(self):
        self._cache = {0: 0, 1: 1}
        self._computed_count = 0

    @property
    def computed_count(self):
        return self._computed_count

    def fib(self, n):
        if not isinstance(n, int) or isinstance(n, bool) or n < 0:
            raise ValueError("n must be a non-negative integer")
        if n in self._cache:
            return self._cache[n]
        for i in range(max(self._cache) + 1, n + 1):
            self._cache[i] = self._cache[i - 1] + self._cache[i - 2]
            self._computed_count += 1
        return self._cache[n]
